                        _ = std.c.write(error_fd, msg.payload.ptr, msg.payload.len);
                    }
                },
                .exit_ack => {
                    if (use_control_mode) {
                        finishControlCommand(&ctrl, saw_error, msg.flags, ctrl_number);
                    }
                    return .{ .exit_code = msg.flags };
                },
                .ready => {
                    return .{ .exit_code = 0, .attached = true };
                },
                .version => {},
                else => {},
